import { DatePipe, ViewportScroller, formatNumber } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import {
  ChangeDetectorRef,
  Component,
  ElementRef,
  EventEmitter,
  HostListener,
  OnInit,
  ViewChild,
} from "@angular/core";
import {
  FormArray,
  FormBuilder,
  FormControl,
  FormGroup,
  ValidatorFn,
  Validators,
} from "@angular/forms";
import { AlertController, Platform } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { IBankSafe } from "src/app/views/Models/Loan/BankSafe";
import { IBranch } from "src/app/views/Models/References/Branch";
import { ICheckSuitableContract } from "src/app/views/Models/Loan/CheckSuitableContract";
import { IInsurance } from "src/app/views/Models/References/Insurance";
import { IIssuingBank } from "src/app/views/Models/Loan/IssuingBank";
import { LoanTypeRef } from "src/app/views/Models/Loan/LoanType";
import { IMakingLoanInsert } from "src/app/views/Models/Loan/MakingLoan";
import { IMakingLoanSearch } from "src/app/views/Models/Loan/MakingLoan";
import {
  IOfficer,
  officerResponseModal,
} from "src/app/views/Models/Officer/Officer";
import { Router, NavigationEnd } from "@angular/router";
import { Subscription } from "rxjs";
import { sortingService } from "src/app/core/services/sorting.service";
import { ScrollingService } from "src/app/core/services/scrolling.service";
import { Funders } from "src/app/views/Models/References/Funders";
import { OfficerService } from "src/app/core/services/officer.service";
import { LoansService } from "src/app/core/services/loans.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";

export interface Iresult {
  client_name: string;
  clnt_code: string;
  status: string;
  reason: string;
}
@Component({
  selector: "app-making-loan",
  templateUrl: "./making-loan.page.html",
  styleUrls: ["./making-loan.page.scss"],
})
export class MakingLoanPage {
  constructor(
    public formBuilder: FormBuilder,
    private env: EnvService,
    private alertService: AlertService,
    private http: HttpClient,
    private authService: MohassilAuthService,
    private datepipe: DatePipe,
    private alertController: AlertController,
    private router: Router,
    private platform: Platform,
    private sortingService: sortingService,
    private ScrollingService: ScrollingService,
    private cdref: ChangeDetectorRef,
    private officerService: OfficerService,
    private loanService: LoansService,
    private referencesService: ReferencesService
  ) {}
  //#region Variables
  IOfficer: officerResponseModal[];
  LoanTypeRefs: LoanTypeRef[];
  IMakingLoanSearch: IMakingLoanSearch[];
  IMakingLoanInsert: IMakingLoanInsert[];
  IIssuingBank: IIssuingBank[];
  IBankSafe: IBankSafe[];
  IInsurance: IInsurance[];
  IBranch: IBranch[];
  InfoOfEveryApplication: IMakingLoanSearch[];
  ResultArray: Iresult[] = []; // this an array to show the result of Creating Loans
  checkboxes: any[] = [];
  SelectedApplicationKeys: any[] = [];
  DefaultOfficerDropDown: string = "0";
  DefaultLoanTypeDropDown: string = "0";
  DefaultBranchDropDown: string = "0";
  officer_key: string;
  all_loan_type: string;
  loan_type: string;
  start_date: string;
  end_date: string;
  showLoader: boolean = false;
  ResultModal: boolean = false;
  backButtonListener: Subscription;
  Funders: Funders[];
  FundingRef: any;
  iscore_external_funding: any;
  isIscore_external_funding: boolean;
  org_code_user_info: string;
  selectDisbOption: boolean = false;
  disbMethods: StaticRef[];
  cashout_code: string = null;
  downPaymentCounter: number = 0;
  isLoanAppsHaveDownPayment: boolean = false;
  //#endregion

  //#region Forms
  isSearchForm: boolean = true;
  isLoanForm: boolean = false;
  isCreateLoanForm: boolean = false;
  isCreateLoanFormValid: boolean = false;
  isSearchFormValid: boolean = true;
  //#endregion

  async ngOnInit() {
    await this.authService.getUserInfo().then((userInfo) => {
      this.org_code_user_info = userInfo.org_code;
    });
    this.registerBackButtonListener();
    this.officerService
      .getAllOfficers()
      .subscribe((officers) => (this.IOfficer = officers));
    this.LoanTypeRefs = await this.loanService.getAllActiveLoanTypes();
    this.IIssuingBank = await this.referencesService.getAllIssuingBanks();
    this.IBankSafe = await this.referencesService.getAllBanksSafe();
    this.IInsurance = await this.referencesService.getAllInsurances();
    this.Funders = await this.referencesService.getAllFunders();
    this.disbMethods = (await this.referencesService.getDisbMethods()).filter(
      (x) => x.ref_code !== "3"
    );
  }
  ngOnDestroy(): void {
    //Handling The BackButton in mobile
    this.backButtonListener.unsubscribe();
  }
  ngAfterContentChecked() {
    this.cdref.detectChanges();
  }
  GetFundingReference($event) {
    if ($event.detail.value != "") {
      this.showLoader = true;
      this.CreateLoanForm.patchValue({ funding_reference_id: null });
      this.http
        .post(this.env.API_URL + "api/LoanApplications/GetFundingReference", {
          org_code: this.org_code_user_info,
          funder_code: $event.detail.value,
        })
        .subscribe({
          next: (data) => {
            console.log(data);
            this.FundingRef = data["fundingRefs"];
            this.iscore_external_funding = data["iscore_external_funding"];
            if (this.iscore_external_funding == "1") {
              this.isIscore_external_funding = true;
              this.CreateLoanForm.controls[
                "funding_reference_id"
              ].setValidators([Validators.required]);
            } else {
              this.isIscore_external_funding = false;
              this.CreateLoanForm.controls[
                "funding_reference_id"
              ].clearValidators();
            }
            this.CreateLoanForm.controls[
              "funding_reference_id"
            ].updateValueAndValidity();
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err);
            this.showLoader = false;
          },
        });
    }
  }
  LoanSearch() {
    if (this.SearchForm.valid == true) {
      this.showLoader = true;
      if (this.SearchForm.value.loan_type == "0") {
        this.all_loan_type = "1";
        this.loan_type = null;
      } else {
        this.all_loan_type = "0";
        this.loan_type = this.SearchForm.value.loan_type;
      }
      this.officer_key = this.SearchForm.value.officer;
      this.start_date = this.SearchForm.value.start_date;
      this.end_date = this.SearchForm.value.end_date;
      this.http
        .post<IMakingLoanSearch[]>(
          this.env.API_URL + "api/LoanApplications/GetMakingLoan",
          {
            officer_key: this.officer_key,
            all_loan_type: this.all_loan_type,
            loan_type: this.loan_type,
            com_dec_date_from: this.start_date,
            com_dec_date_to: this.end_date,
          }
        )
        .subscribe({
          next: async (data) => {
            this.IMakingLoanSearch = data;
            this.downPaymentCheck();
            console.log("IMakingLoanSearch: ", this.IMakingLoanSearch);
            for (let i = 0; i < this.IMakingLoanSearch.length; ) {
              this.IMakingLoanSearch[i].aprv_am = formatNumber(
                Number(parseInt(this.IMakingLoanSearch[i].aprv_am)),
                "en-US",
                "1.0-0"
              );
              this.IMakingLoanSearch[i].com_dec_date = this.datepipe.transform(
                this.IMakingLoanSearch[i].com_dec_date,
                "yyyy-MM-dd"
              );
              i++;
            }
            if (this.IMakingLoanSearch.length == 0) {
              await this.alertService.showAlertError(
                "لا يوجد قروض للانشاء",
                false
              );
              this.showLoader = false;
            } else {
              this.isSearchForm = false;
              this.isLoanForm = true;
              this.isCreateLoanForm = true;
              this.showLoader = false;
            }
          },
          error: (err) => {
            this.showLoader = false;
          },
        });
    }
  }
  async submit() {
    this.isCreateLoanFormValid = true;
    if (this.CreateLoanForm.valid == true) {
      if (
        await this.alertService.SaveAlert(
          "هل أنت متأكد أنك تريد تنفيذ هذة العملية؟ "
        )
      ) {
        this.isCreateLoanFormValid = true;

        this.ResultArray = [];
        this.SelectedApplicationKeys = this.getDistinctValues(
          this.getCheckedCheckboxes(),
          "application_key"
        );
        if (this.CreateLoanForm.valid == true) {
          if (this.SelectedApplicationKeys.length > 0) {
            this.InfoOfEveryApplication = this.SelectedApplicationKeys.map(
              (application_key) =>
                this.IMakingLoanSearch.find(
                  (x) => x.application_key === application_key
                )
            );
            this.showLoader = true;
            if (this.CreateLoanForm.value.inssurance != null) {
              for (let i = 0; i < this.InfoOfEveryApplication.length; i++) {
                let client_key =
                  this.InfoOfEveryApplication[i].client_key.toString();
                let application_key =
                  this.InfoOfEveryApplication[i].application_key.toString();
                let client_type_code =
                  this.InfoOfEveryApplication[i].client_type_code.toString();
                let contract_id =
                  this.CreateLoanForm.value.inssurance.toString();
                this.http
                  .post<ICheckSuitableContract[]>(
                    this.env.API_URL + "api/Insurance/CheckSuitableContract",
                    {
                      client_key: client_key,
                      application_key: application_key,
                      client_type_code: client_type_code,
                      contract_id: contract_id,
                    }
                  )
                  .subscribe({
                    next: (data) => {
                      if (i == this.InfoOfEveryApplication.length - 1) {
                        this.CreateLoan(this.InfoOfEveryApplication);
                      }
                    },
                    error: (err) => {
                      this.PushMethodIntoResultArray(
                        this.InfoOfEveryApplication[i].client_name,
                        this.InfoOfEveryApplication[i].clnt_code.toString(),
                        "فشل",
                        err.error
                      );
                      if (i == this.InfoOfEveryApplication.length - 1) {
                        this.ResultModal = true;
                      }
                      this.showLoader = false;
                    },
                  });
              }
            } else if (this.CreateLoanForm.value.inssurance == null) {
              this.CreateLoan(this.InfoOfEveryApplication);
            }
          } else if (this.SelectedApplicationKeys.length == 0) {
            await this.alertService.showAlertError(
              "برجاء اختيار القروض",
              false
            );
          }
        }
      }
    } else {
      this.ScrollingService.findInvalidControls(this.CreateLoanForm);
    }
  }
  CreateLoan(InfoOfEveryApplication) {
    this.showLoader = true;
    for (let index = 0; index < this.InfoOfEveryApplication.length; index++) {
      let bankSafe = this.CreateLoanForm.value.selectSafe;
      let issuingbank = this.CreateLoanForm.value.issuingbank;
      let dec_effective_date = this.CreateLoanForm.value.dec_effective_date;
      let loan_vouch_char = this.InfoOfEveryApplication[index].loan_vouch;
      let funder_code = this.CreateLoanForm.controls["funder_code"].value;
      let funding_reference_id =
        this.CreateLoanForm.controls["funding_reference_id"].value;
      let disb_method = this.CreateLoanForm.controls["disb_method"].value;
      if (loan_vouch_char != null) {
        loan_vouch_char = loan_vouch_char.toString();
      }
      this.http
        .post<IMakingLoanInsert[]>(
          this.env.API_URL + "api/LoanApplications/MakingLoanInsert",
          {
            loan_vouch_char: loan_vouch_char,
            dec_effective_date: dec_effective_date,
            bank_code: issuingbank.toString(),
            inst_cur_bank: bankSafe.toString(),
            payments_shift:
              InfoOfEveryApplication[index].payments_shift.toString(),
            application_key:
              InfoOfEveryApplication[index].application_key.toString(),
            funder_code: funder_code,
            funding_reference_id: funding_reference_id,
            uuc: InfoOfEveryApplication[index].uuc.toString(),
            cashout_code: this.cashout_code
              ? this.cashout_code.toString()
              : null,
            disb_method: disb_method.toString(),
          }
        )
        .subscribe({
          next: (data) => {
            this.PushMethodIntoResultArray(
              InfoOfEveryApplication[index].client_name,
              InfoOfEveryApplication[index].clnt_code.toString(),
              "نجح",
              "لا يوجد"
            );
            if (index == InfoOfEveryApplication.length - 1) {
              this.ResultModal = true;
              this.showLoader = false;
            }
          },
          error: (err) => {
            this.PushMethodIntoResultArray(
              InfoOfEveryApplication[index].client_name,
              InfoOfEveryApplication[index].clnt_code.toString(),
              "فشل",
              err.error
            );
            if (index == InfoOfEveryApplication.length - 1) {
              this.ResultModal = true;
              this.showLoader = false;
            }
          },
        });
    }
  }
  dismissModal() {
    this.ResultModal = false;
    this.LoanSearch();
    this.LoanForm.patchValue({ checkBox: false });
    this.LoanForm.patchValue({ loan_vouch: null });
  }
  // Pushes the client details into the ResultArray
  PushMethodIntoResultArray(
    client_name,
    client_code: string,
    status: string,
    reason: string
  ) {
    this.ResultArray.push({
      client_name,
      clnt_code: client_code,
      status,
      reason,
    });
  }
  BackToSearchForm() {
    this.IMakingLoanSearch = [];
    this.isCreateLoanFormValid = false;
    this.LoanForm.patchValue({ checkBox: false });
    this.LoanForm.patchValue({ loan_vouch: null });
    this.isLoanForm = false;
    this.isCreateLoanForm = false;
    this.isSearchForm = true;
    //this.cashout_code = null;
    this.downPaymentCounter = 0;
  }
  onCheckboxChange(event, loan) {
    if (event.target.checked) {
      loan.isChecked = true;
      this.checkboxes.push(loan);
    } else {
      const index = this.checkboxes.indexOf(loan);
      if (index > -1) {
        loan.isChecked = false;
        this.checkboxes.splice(index, 1);
      }
    }
  }
  getCheckedCheckboxes() {
    return (
      this.checkboxes.filter((loan) => loan && loan.isChecked),
      this.checkboxes.filter((loan) => loan && loan.isChecked)
    );
  }
  getDistinctValues(data: any[], distinct_name: string): any[] {
    const values = data.map((item: any) => item[distinct_name]);
    const distinctValues = values.filter(
      (value: any, index: number, array: any[]) =>
        array.indexOf(value) === index
    );
    return distinctValues;
  }
  SearchForm: FormGroup = this.formBuilder.group({
    officer: [""],
    start_date: [
      this.datepipe.transform(new Date(), "yyyy-MM-01"),
      [
        Validators.required,
        Validators.pattern(
          "((?:19|20)[0-9][0-9])-(0?[1-9]|1[012])-(0?[1-9]|[12][0-9]|3[01])"
        ),
        this.noWhitespaceValidator,
      ],
    ],
    end_date: [
      this.datepipe.transform(new Date(), "yyyy-MM-dd"),
      [
        Validators.required,
        Validators.pattern(
          "((?:19|20)[0-9][0-9])-(0?[1-9]|1[012])-(0?[1-9]|[12][0-9]|3[01])"
        ),
        this.noWhitespaceValidator,
      ],
    ],
    loan_type: [""],
  });
  CreateLoanForm: FormGroup = this.formBuilder.group({
    issuingbank: ["", Validators.required],
    selectSafe: ["", Validators.required],
    inssurance: [null],
    dec_effective_date: [
      this.datepipe.transform(new Date(), "yyyy-MM-dd"),
      [
        Validators.required,
        Validators.pattern(
          "((?:19|20)[0-9][0-9])-(0?[1-9]|1[012])-(0?[1-9]|[12][0-9]|3[01])"
        ),
        this.noWhitespaceValidator,
      ],
    ],
    funder_code: ["", Validators.required],
    funding_reference_id: [""],
    disb_method: ["", Validators.required],
  });
  LoanForm: FormGroup = this.formBuilder.group({
    loan_vouch: [null],
    checkBox: [false],
  });

  registerBackButtonListener(): void {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      10,
      (next) => {
        this.backButton();
      }
    );
  }
  backButton(): void {
    if (this.isSearchForm == true) {
      this.router.navigate(["/home"]);
    } else if (this.isCreateLoanForm == true && this.isLoanForm == true) {
      this.BackToSearchForm();
    }
  }
  get GetCreateLoanForm() {
    return this.CreateLoanForm.controls;
  }
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace = (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }
  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
  }
  selectBank(ev: any) {
    let curBank = ev.target.value;
    this.cashout_code = this.IIssuingBank.find(
      (x) => x.bank_code === curBank
    ).cashout_code;
    if (!this.cashout_code) {
      this.selectDisbOption = true;
      this.CreateLoanForm.controls.disb_method.reset();
    } else {
      this.selectDisbOption = false;
      this.CreateLoanForm.patchValue({
        disb_method: "3",
      });
    }
  }
  downPaymentCheck() {
    this.IMakingLoanSearch.forEach((app) => {
      if (app.down_payment != 0) {
        this.downPaymentCounter++;
      }
    });
    if (this.downPaymentCounter != 0) {
      //ther is no loanApp's have dp
      this.isLoanAppsHaveDownPayment = true;
    } else {
      this.isLoanAppsHaveDownPayment = false;
    }
  }
}
